 71→interface MessageItemProps {
 72→  message: Message;
 73→  isLoading: boolean;
 74→  isStreaming?: boolean;
 75→  secondaryMessage?: Message;
 76→  displayVariant?: 'default' | 'thinking';
 77→  thinkingDisplayMode?: 'collapsible' | 'inline';
 78→  isSelected?: boolean;
 79→  onAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
 80→  onSelectToolDetail?: (messageId: string) => void;
 81→}
 82→
 83→export function MessageItem({
 84→  message,
 85→  isLoading,
 86→  isStreaming = false,
 87→  secondaryMessage,
 88→  displayVariant = 'default',
 89→  thinkingDisplayMode = 'collapsible',
 90→  isSelected = false,
 91→  onSelectToolDetail,
 92→  onAskUserSubmit
 93→}: MessageItemProps) {
 94→  const isThinkingVariant = displayVariant === 'thinking';
 95→  const label = getEventLabel(message);
 96→  const isToolErrorEvent = message.event === EVENT_ERROR && !!message.toolName;
 97→  const isError = message.event === EVENT_ERROR && !isToolErrorEvent;
 98→  const isAskUser = message.event === EVENT_INTERRUPT;
 99→  const isAskUserForm = isAskUser && message.askUser?.kind === 'form';
100→  const isUser = message.role === 'user';
101→  const isToolMessage = isToolCallStep(message.event) || message.event === EVENT_TOOL_OUTPUT || isToolErrorEvent;
102→  const isStatusMessage = message.event === EVENT_AGENT_START || message.event === EVENT_CONTEXT_SUMMARIZED;
103→  const hasThinking = typeof message.thinking === 'string' && message.thinking.trim().length > 0;
104→  const preview = extractSingleLinePreview(message.content);
105→  const secondaryPreview = secondaryMessage ? extractSingleLinePreview(secondaryMessage.content) : '';
106→  const outputLength = secondaryMessage?.outputLength ?? message.outputLength;
107→  const detailStatus = getDetailStatus(message);
108→  const hideCompletedStatus = shouldHideCompletedStatus(message);
109→
110→  if (isError) {
111→    return (
112→      <div className="w-full min-w-0 rounded-2xl border border-destructive/30 bg-destructive/10 px-5 py-3.5 shadow-sm !mt-3">
113→        <div className="flex items-start gap-2 text-destructive">
114→          <AlertTriangle className="mt-0.5 h-4 w-4 shrink-0" />
115→          <div>
116→            <div className="mb-1 text-[10px] font-semibold uppercase tracking-wide opacity-70">Error</div>
117→            <div className="whitespace-pre-wrap text-sm">{message.content}</div>
118→          </div>
119→        </div>
120→      </div>
121→    );
122→  }
123→
124→  if (isAskUser) {
125→    return (
126→      <div
127→        className={cn(
128→          'w-full min-w-0 rounded-2xl border border-amber-300 bg-amber-50 px-5 py-3.5 shadow-sm dark:border-amber-700 dark:bg-amber-950/30 !mt-3',
129→          isAskUserForm && 'px-4 py-4',
130→        )}
131→      >
132→        <div className="mb-1.5 text-[10px] font-semibold uppercase tracking-wide text-amber-600 dark:text-amber-400">
133→          需要您提供信息
134→        </div>
135→        {isAskUserForm && message.askUser ? (
136→          <AskUserFormCard
137→            data={message.askUser as Extract<typeof message.askUser, { kind: 'form' }>}
138→            submitting={isLoading}
139→            submittedValues={message.askUser.answer}
140→            readonlyPreview={message.askUser.isPreview}
141→            onSubmit={values => onAskUserSubmit(message.askUser?.interruptId, values)}
142→          />
143→        ) : (
144→          <MarkdownRenderer content={message.content} isAnimating={isStreaming} />
145→        )}
146→      </div>
147→    );
148→  }
149→
150→  if (isToolMessage) {
151→    if (message.toolDetail) {
152→      if (message.toolDetail.kind === 'execute') {
153→        const command = message.toolDetail.code || message.toolDetail.title;
154→        const output = message.toolDetail.output || '';
155→        const status = hideCompletedStatus ? '' : (detailStatus || '');
156→        const isExecuteError = message.isError || message.toolDetail.status === 'error';
157→        const commandPanelClassName = isExecuteError
158→          ? 'border-destructive/25 bg-destructive/5'
159→          : 'border-emerald-500/20 bg-emerald-500/5';
160→        const commandHeaderClassName = isExecuteError
161→          ? 'border-destructive/25 text-destructive'
162→          : 'border-emerald-500/20 text-emerald-600 dark:text-emerald-400';
163→        const outputPanelClassName = isExecuteError
164→          ? 'border-destructive/25 bg-destructive/5'
165→          : 'border-sky-500/20 bg-sky-500/5';
166→        const outputHeaderClassName = isExecuteError
167→          ? 'border-destructive/25 text-destructive'
168→          : 'border-sky-500/20 text-sky-600 dark:text-sky-400';
169→
170→        return (
171→          <details className="group w-full overflow-hidden rounded-xl border border-border/60 bg-background/40" open={false}>
172→            <summary className="flex cursor-pointer list-none items-center gap-3 px-3 py-2 [&::-webkit-details-marker]:hidden">
173→              <ChevronRight className="h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200 group-open:rotate-90" />
174→              <div className={cn(
175→                'flex items-center gap-1.5 rounded-md border bg-background px-2 py-1 text-xs font-semibold',
176→                isExecuteError
177→                  ? 'border-destructive/30 text-destructive'
178→                  : 'border-border/50 text-foreground/80',
179→              )}>
180→                <TerminalSquare className={cn('h-3.5 w-3.5', isExecuteError ? 'text-destructive' : 'text-emerald-500')} />
181→                <span>Bash</span>
182→              </div>
183→              <div className="min-w-0 flex-1">
184→                {status ? (
185→                  <div className={cn('truncate text-xs', isExecuteError ? 'text-destructive/80' : 'text-muted-foreground')}>
186→                    {status}
187→                  </div>
188→                ) : null}
189→              </div>
190→              <OutputLengthBadge outputLength={outputLength} className="bg-muted text-muted-foreground/80" />
191→            </summary>
192→
193→            <div className="space-y-3 border-t border-border/50 px-3 py-3">
194→              <div className={cn('rounded-lg border', commandPanelClassName)}>
195→                <div className={cn('border-b px-3 py-1.5 text-[11px] font-semibold uppercase tracking-wide', commandHeaderClassName)}>
196→                  Command
197→                </div>
198→                <pre className="overflow-x-auto whitespace-pre-wrap px-3 py-2 text-xs leading-6 text-foreground">{command}</pre>
199→              </div>
200→
201→              <div className={cn('rounded-lg border', outputPanelClassName)}>
202→                <div className={cn('border-b px-3 py-1.5 text-[11px] font-semibold uppercase tracking-wide', outputHeaderClassName)}>
203→                  Output
204→                </div>
205→                <pre className="overflow-x-auto whitespace-pre-wrap px-3 py-2 text-xs leading-6 text-foreground">
206→                  {output || '[no output]'}
207→                </pre>
208→              </div>
209→            </div>
210→          </details>
211→        );
212→      }
213→
214→      return (
215→        <button
216→          type="button"
217→          onClick={() => onSelectToolDetail?.(message.id)}
218→          className={cn(
219→            'group flex w-full min-w-0 items-center gap-3 rounded-xl border px-3 py-2 text-left transition-colors',
220→            isSelected
221→              ? 'border-primary/40 bg-primary/5'
222→              : 'border-border/50 bg-muted/30 hover:bg-muted/50',
223→            message.isError ? 'text-destructive' : 'text-foreground/85',
224→          )}
225→        >
226→          <div className={cn(
227→            'flex items-center gap-1.5 shrink-0 rounded-md border px-2 py-1 text-xs font-semibold',
228→            message.isError
229→              ? 'border-destructive/30 bg-destructive/10 text-destructive'
230→              : 'border-border/50 bg-background text-foreground/80',
231→          )}>
232→            <Wrench className={cn('h-3.5 w-3.5', message.isError ? 'text-destructive' : 'text-amber-500')} />
233→            <span>{message.toolName || 'tool'}</span>
234→          </div>
235→
236→          <div className="min-w-0 flex-1">
237→            <div className="truncate text-sm font-medium">{message.toolDetail.title}</div>
238→            {!hideCompletedStatus && detailStatus ? (
239→              <div className={cn(
240→                'truncate text-xs',
241→                message.isError ? 'text-destructive/80' : 'text-muted-foreground',
242→              )}>
243→                {detailStatus}
244→              </div>
245→            ) : null}
246→          </div>
247→
248→          <OutputLengthBadge outputLength={outputLength} className="bg-muted text-muted-foreground/80" />
249→        </button>
250→      );
251→    }
252→
253→    const isToolError = secondaryMessage?.isError ?? message.isError;
254→
255→    return (
256→      <TooltipProvider delayDuration={250}>
257→        <Tooltip>
258→          <TooltipTrigger asChild>
259→            <div
260→              className={cn(
261→                'group flex w-full min-w-0 items-center gap-2 py-1',
262→                isThinkingVariant ? 'text-xs' : 'text-sm',
263→                isToolError
264→                  ? 'text-destructive'
265→                  : isThinkingVariant
266→                    ? 'text-muted-foreground/75'
267→                    : 'text-muted-foreground',
268→              )}
269→            >
270→              <div className={cn(
271→                'flex items-center gap-1.5 shrink-0 rounded-md border px-2 py-0.5',
272→                isToolError
273→                  ? 'border-destructive/30 bg-destructive/10 text-destructive'
274→                  : isThinkingVariant
275→                    ? 'border-border/40 bg-muted/35 text-foreground/70'
276→                    : 'border-border/50 bg-muted/50 text-foreground/80'
277→              )}>
278→                <Wrench className={cn("h-3.5 w-3.5", isToolError ? "text-destructive" : "text-amber-500")} />
279→                <span className="font-semibold text-xs leading-none">{message.toolName || 'tool'}</span>
280→              </div>
281→
282→              <div className="flex-1 min-w-0 flex items-center gap-2 overflow-hidden text-xs">
283→                {secondaryMessage && secondaryPreview ? (
284→                  <span className={cn("truncate leading-none", isToolError ? "text-destructive/80" : isThinkingVariant ? "text-muted-foreground/65" : "text-muted-foreground/80")}>{secondaryPreview}</span>
285→                ) : preview ? (
286→                  <span className={cn("truncate leading-none", isToolError ? "text-destructive/80" : isThinkingVariant ? "text-muted-foreground/65" : "text-muted-foreground/80")}>{preview}</span>
287→                ) : null}
288→              </div>
289→
290→              <OutputLengthBadge
291→                outputLength={outputLength}
292→                isError={!!isToolError}
293→                className="leading-none"
294→              />
295→            </div>
296→          </TooltipTrigger>
297→          <TooltipContent
298→            side="top"
299→            align="start"
300→            className="max-w-xl max-h-[400px] overflow-y-auto whitespace-pre-wrap rounded-lg border border-border bg-popover px-3 py-2 font-mono text-[11px] leading-relaxed text-popover-foreground shadow-lg"
301→          >
302→            {secondaryMessage ? (
303→              <div className="space-y-3">
304→                <div>
305→                  <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">INPUT</div>
306→                  <div className={message.isError ? "text-destructive" : ""}>{message.content}</div>
307→                </div>
308→                <div>
309→                  <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">OUTPUT</div>
310→                  <div className={secondaryMessage.isError ? "text-destructive" : ""}>{secondaryMessage.content}</div>
311→                </div>
312→              </div>
313→            ) : (
314→              <div>
315→                <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">
316→                  {message.event === EVENT_TOOL_OUTPUT ? 'OUTPUT' : 'INPUT'}
317→                </div>
318→                <div className={message.isError ? "text-destructive" : ""}>{message.content}</div>
319→              </div>
320→            )}
321→          </TooltipContent>
322→        </Tooltip>
323→      </TooltipProvider>
324→    );
325→  }
326→
327→  if (isUser) {
328→    return (
329→      <div className="max-w-[85%] rounded-2xl rounded-tr-none bg-primary px-5 py-3.5 text-primary-foreground shadow-sm">
330→        <div className="whitespace-pre-wrap">{message.content}</div>
331→      </div>
332→    );
333→  }
334→
335→  if (isStatusMessage) {
336→    return (
337→      <div className={cn('flex min-w-0 items-baseline gap-2 py-1', isThinkingVariant && 'text-xs')}>
338→        {label && (
339→          <div className={cn('text-[10px] uppercase tracking-wide', isThinkingVariant ? 'text-muted-foreground/65' : 'text-muted-foreground/80')}>
340→            {label}
341→          </div>
342→        )}
343→        <div className={cn(isThinkingVariant ? 'text-[11px] font-medium text-muted-foreground/75' : 'text-sm font-medium text-foreground/80')}>{message.content}</div>
344→      </div>
345→    );
346→  }
347→
348→  return (
349→    <div className="min-w-0 space-y-2 text-sm leading-relaxed">
350→      {label && (
351→        <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground/80">
352→          {label}
353→        </div>
354→      )}
355→      {hasThinking && thinkingDisplayMode === 'collapsible' && (
356→        <details className="min-w-0 overflow-hidden rounded-lg border border-border/70 bg-muted/30 px-3 py-2">
357→          <summary className="cursor-pointer text-xs font-medium text-muted-foreground">
358→            思考过程
359→          </summary>
360→          <div className="mt-2 min-w-0 overflow-hidden">
361→            <ThinkingText content={message.thinking || ''} />
362→          </div>
363→        </details>
364→      )}
365→      {hasThinking && thinkingDisplayMode === 'inline' && (
366→        <div className="min-w-0 overflow-hidden text-muted-foreground/75">
367→          <ThinkingText content={message.thinking || ''} />
368→        </div>
369→      )}
370→      {message.content && <MarkdownRenderer content={message.content} isAnimating={isStreaming} />}
371→    </div>
372→  );
373→}
