 1→export interface TokenUsageSnapshot {
 2→  inputTokens: number;
 3→  outputTokens: number;
 4→  totalTokens: number;
 5→  promptTokens?: number;
 6→  completionTokens?: number;
 7→  cachedInputTokens?: number;
 8→  reasoningOutputTokens?: number;
 9→}
10→
11→function asRecord(value: unknown): Record<string, unknown> | undefined {
12→  return value && typeof value === 'object' ? (value as Record<string, unknown>) : undefined;
13→}
14→
15→function asNumber(value: unknown): number | undefined {
16→  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
17→}
18→
19→function hasAnyNumericKey(record: Record<string, unknown> | undefined, keys: string[]): boolean {
20→  if (!record) {
21→    return false;
22→  }
23→  return keys.some(key => typeof record[key] === 'number' && Number.isFinite(record[key] as number));
24→}
25→
26→export function parseTokenUsageFromAssistantEndData(data: unknown): TokenUsageSnapshot | undefined {
27→  const eventData = asRecord(data);
28→  const nestedUsage = asRecord(eventData?.usage);
29→  const directUsage = hasAnyNumericKey(eventData, ['inputTokens', 'outputTokens', 'totalTokens', 'input_tokens', 'output_tokens', 'total_tokens']) ? eventData : undefined;
30→  const usage = nestedUsage ?? directUsage;
31→  if (!usage) {
32→    return undefined;
33→  }
34→
35→  const inputTokens = asNumber(usage.inputTokens) ?? asNumber(usage.input_tokens);
36→  const outputTokens = asNumber(usage.outputTokens) ?? asNumber(usage.output_tokens);
37→  const totalTokens =
38→    asNumber(usage.totalTokens) ??
39→    asNumber(usage.total_tokens) ??
40→    (typeof inputTokens === 'number' && typeof outputTokens === 'number' ? inputTokens + outputTokens : undefined);
41→  if (typeof inputTokens !== 'number' || typeof outputTokens !== 'number' || typeof totalTokens !== 'number') {
42→    return undefined;
43→  }
44→
45→  const promptTokens = asNumber(usage.promptTokens) ?? asNumber(usage.prompt_tokens);
46→  const completionTokens = asNumber(usage.completionTokens) ?? asNumber(usage.completion_tokens);
47→  const cachedInputTokens =
48→    asNumber(usage.cachedInputTokens) ??
49→    asNumber(usage.cached_input_tokens) ??
50→    asNumber(usage.prompt_cache_hit_tokens);
51→  const reasoningOutputTokens =
52→    asNumber(usage.reasoningOutputTokens) ??
53→    asNumber(usage.reasoning_output_tokens);
54→
55→  return {
56→    inputTokens,
57→    outputTokens,
58→    totalTokens,
59→    ...(typeof promptTokens === 'number' ? { promptTokens } : {}),
60→    ...(typeof completionTokens === 'number' ? { completionTokens } : {}),
61→    ...(typeof cachedInputTokens === 'number' ? { cachedInputTokens } : {}),
62→    ...(typeof reasoningOutputTokens === 'number' ? { reasoningOutputTokens } : {}),
63→  };
64→}
65→
66→export function getTokenUsagePercent(used: number, capacity: number): number {
67→  if (capacity <= 0) {
68→    return 0;
69→  }
70→  return Math.min(100, Math.max(0, Math.round((used / capacity) * 100)));
71→}
