 37→function SubagentPreviewText({
 38→  text,
 39→  enableTooltip,
 40→  className,
 41→}: {
 42→  text: string;
 43→  enableTooltip: boolean;
 44→  className?: string;
 45→}) {
 46→  const textRef = useRef<HTMLDivElement>(null);
 47→  const [isOverflowing, setIsOverflowing] = useState(false);
 48→
 49→  useEffect(() => {
 50→    if (!enableTooltip) {
 51→      setIsOverflowing(false);
 52→      return;
 53→    }
 54→
 55→    const element = textRef.current;
 56→    if (!element) {
 57→      return;
 58→    }
 59→
 60→    const checkOverflow = () => {
 61→      setIsOverflowing(element.scrollWidth > element.clientWidth);
 62→    };
 63→
 64→    checkOverflow();
 65→
 66→    if (typeof ResizeObserver !== 'undefined') {
 67→      const observer = new ResizeObserver(checkOverflow);
 68→      observer.observe(element);
 69→      return () => observer.disconnect();
 70→    }
 71→
 72→    window.addEventListener('resize', checkOverflow);
 73→    return () => window.removeEventListener('resize', checkOverflow);
 74→  }, [enableTooltip, text]);
 75→
 76→  const content = (
 77→    <div ref={textRef} className={className}>
 78→      {text}
 79→    </div>
 80→  );
 81→
 82→  if (!enableTooltip || !isOverflowing) {
 83→    return content;
 84→  }
 85→
 86→  return (
 87→    <TooltipProvider delayDuration={150}>
 88→      <Tooltip>
 89→        <TooltipTrigger asChild>{content}</TooltipTrigger>
 90→        <TooltipContent side="top" align="start" className="max-w-sm p-3">
 91→          <div className="whitespace-pre-wrap break-words text-xs leading-5">{text}</div>
 92→        </TooltipContent>
 93→      </Tooltip>
 94→    </TooltipProvider>
 95→  );
 96→}
