585→export function MessageList({
586→  messages,
587→  isLoading,
588→  onAskUserSubmit,
589→  scrollRef,
590→  selectedDetailMessageId,
591→  selectedSubagentKey,
592→  onSelectToolDetail,
593→  onSelectSubagent,
594→}: MessageListProps) {
595→  const { blocks, lastVisibleMessage } = useMemo(() => {
596→    const visibleMessages = messages.filter(message => {
597→      if (message.event !== EVENT_TODO_UPDATE) {
598→        return true;
599→      }
600→
601→      return message.source?.kind === 'subagent';
602→    });
603→
604→    return {
605→      blocks: buildBlocks(visibleMessages),
606→      lastVisibleMessage: visibleMessages.at(-1),
607→    };
608→  }, [messages]);
609→
610→  const isLoadingAfterUser = isLoading && lastVisibleMessage?.role === 'user';
611→  const activeAssistantMessageId =
612→    isLoading && lastVisibleMessage?.role === 'assistant' ? lastVisibleMessage.id : undefined;
613→  // The last visible assistant message, used for subagent active detection
614→  const lastAssistantMessageId = lastVisibleMessage?.role === 'assistant' ? lastVisibleMessage.id : undefined;
615→  // streamingMessageId 必须指向最后一条正在接收内容的 assistant 消息，
616→  // 而不是最后一条可见消息（后者可能是 subagent 推送的 agent-end 等空消息），
617→  // 否则 markdown 渲染器会过早退出流式态，导致内容看起来被截断。
618→  const streamingMessageId = useMemo(() => {
619→    if (!isLoading) return undefined;
620→    // 只有当最后一条可见消息本身就是 main source 的 assistant 事件时，才标记为流式中。
621→    // 如果最新消息是 tool-call/agent-end 等，说明 assistant 文本块已经结束，
622→    // 不应再给旧的 assistant 消息设置 isAnimating=true，否则 markdown 渲染器会
623→    // 以不完整内容模式渲染，导致表格等 markdown 结构显示损坏。
624→    const last = lastVisibleMessage;
625→    if (last?.event === EVENT_ASSISTANT && (!last.source || last.source.kind === 'main')) {
626→      return last.id;
627→    }
628→    return undefined;
629→  }, [isLoading, lastVisibleMessage]);
630→
631→  return (
632→    <div className="mx-auto min-h-full max-w-3xl space-y-2 pb-4">
633→      {blocks.map((block, blockIndex) => {
634→        if (block.type === 'user') {
635→          return (
636→            <div key={block.message.id} className="relative">
637→              <UserAvatar />
638→              <div className="flex justify-end">
639→                <MessageItem
640→                  message={block.message}
641→                  isLoading={isLoading}
642→                  isStreaming={block.message.id === streamingMessageId}
643→                  onAskUserSubmit={onAskUserSubmit}
644→                />
645→              </div>
646→            </div>
647→          );
648→        }
649→
650→        const contentViews = buildAssistantContentViews(block.messages, streamingMessageId, activeAssistantMessageId);
651→        // Active if this block contains the last visible assistant message and we're still loading
652→        const isActiveAssistantBlock = Boolean(
653→          isLoading && lastAssistantMessageId && block.messages.some(message => message.id === lastAssistantMessageId),
654→        );
655→        const callbacks: MessageRenderCallbacks = {
656→          isLoading,
657→          selectedDetailMessageId,
658→          selectedSubagentKey,
659→          onAskUserSubmit,
660→          onSelectToolDetail,
661→          onSelectSubagent,
662→        };
663→
664→        return (
665→          <div key={`assistant-${blockIndex}`} className="relative">
666→            <AssistantAvatar isActive={isActiveAssistantBlock} />
667→            <div className="min-h-8 space-y-1">
668→              {contentViews.map(contentView =>
669→                contentView.type === 'subagent'
670→                  ? renderSubagentContentView(contentView, callbacks)
671→                  : renderMainContentView(contentView, streamingMessageId, callbacks),
672→              )}
673→            </div>
674→          </div>
675→        );
676→      })}
677→
678→      {isLoadingAfterUser && (
679→        <div className="relative">
680→          <AssistantAvatar isLoading isActive />
681→          <div className="min-h-8" />
682→        </div>
683→      )}
684→
685→      <div ref={scrollRef} />
686→    </div>
687→  );
688→}
