  1→import type { Message, TodoItem } from '@/types';
  2→import { EVENT_ASSISTANT, EVENT_TOOL_CALL_RESULT } from '@/lib/const';
  3→import { extractSingleLinePreview, extractTaskDescription } from '@/lib/chatUtils';
  4→
  5→interface BuildSubagentDisplayStateOptions {
  6→  key: string;
  7→  label: string;
  8→  messages: Message[];
  9→}
 10→
 11→export interface SubagentDisplayState {
 12→  key: string;
 13→  label: string;
 14→  taskDescription?: string;
 15→  latestAssistantContent?: string;
 16→  preview: string;
 17→  completed: boolean;
 18→  error?: boolean;
 19→  todos: TodoItem[];
 20→  showTodoPanel: boolean;
 21→}
 22→
 23→function getTaskDescription(messages: Message[]): string | undefined {
 24→  for (const message of messages) {
 25→    if (message.toolName !== 'task') {
 26→      continue;
 27→    }
 28→
 29→    const description = extractTaskDescription(message.content);
 30→    if (description) {
 31→      return description;
 32→    }
 33→  }
 34→
 35→  return undefined;
 36→}
 37→
 38→function getLatestAssistantContent(messages: Message[]): string | undefined {
 39→  for (let index = messages.length - 1; index >= 0; index -= 1) {
 40→    const message = messages[index];
 41→    if (message?.event !== EVENT_ASSISTANT || !message.content.trim()) {
 42→      continue;
 43→    }
 44→
 45→    return extractSingleLinePreview(message.content, 64);
 46→  }
 47→
 48→  return undefined;
 49→}
 50→
 51→function getLatestSubagentTodos(messages: Message[]): TodoItem[] {
 52→  for (let index = messages.length - 1; index >= 0; index -= 1) {
 53→    const message = messages[index];
 54→    if (Array.isArray(message?.todos)) {
 55→      return message.todos;
 56→    }
 57→  }
 58→
 59→  return [];
 60→}
 61→
 62→function isSubagentCompleted(messages: Message[]): boolean {
 63→  const lastMessage = messages.at(-1);
 64→  if (lastMessage?.event === EVENT_TOOL_CALL_RESULT && lastMessage?.toolName === 'task') {
 65→    return true;
 66→  }
 67→  return false;
 68→}
 69→
 70→function hasSubagentError(messages: Message[]): boolean {
 71→  return messages.some(
 72→    message => message.event === EVENT_TOOL_CALL_RESULT && message.toolName === 'task' && !!message.isError,
 73→  );
 74→}
 75→
 76→export function buildSubagentDisplayState({
 77→  key,
 78→  label,
 79→  messages,
 80→}: BuildSubagentDisplayStateOptions): SubagentDisplayState {
 81→  const taskDescription = getTaskDescription(messages);
 82→  const latestAssistantContent = getLatestAssistantContent(messages);
 83→  const todos = getLatestSubagentTodos(messages);
 84→  const completed = isSubagentCompleted(messages);
 85→  const error = hasSubagentError(messages);
 86→  const preview = error
 87→    ? '执行失败'
 88→    : completed
 89→      ? 'completed'
 90→      : latestAssistantContent || taskDescription || '处理中...';
 91→
 92→  return {
 93→    key,
 94→    label,
 95→    taskDescription,
 96→    latestAssistantContent,
 97→    preview,
 98→    completed,
 99→    error,
100→    todos,
101→    showTodoPanel: !completed && todos.length > 0,
102→  };
103→}
