  1→import { useEffect, useMemo, useRef, useState } from 'react';
  2→import { Button } from '@/components/ui/button';
  3→import { Textarea } from '@/components/ui/textarea';
  4→import { TodoListBlock } from '@/components/chat/TodoListBlock';
  5→import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
  6→import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
  7→import { Check, ChevronDown, Send } from 'lucide-react';
  8→import type { TodoTreeItem } from '@/types';
  9→import { cn } from '@/lib/utils';
 10→import { type ModelId } from '@/lib/const';
 11→import { getTokenUsagePercent } from '@/lib/tokenUsage';
 12→import { filterSkillNames, findSkillCommand, insertSkillCommand } from './chatInputUtils';
 13→
 14→interface ChatInputProps {
 15→  input: string;
 16→  isLoading: boolean;
 17→  todoTree?: TodoTreeItem[];
 18→  skills?: string[];
 19→  availableModels?: ModelId[];
 20→  selectedModel: ModelId;
 21→  onModelChange: (model: ModelId) => void;
 22→  modelSelectionDisabled?: boolean;
 23→  tokenUsage: { used: number; capacity: number };
 24→  onInputChange: (value: string) => void;
 25→  onSend: () => void;
 26→}
 27→
 28→export function ChatInput({
 29→  input,
 30→  isLoading,
 31→  todoTree = [],
 32→  skills = [],
 33→  availableModels = [],
 34→  selectedModel,
 35→  onModelChange,
 36→  modelSelectionDisabled = false,
 37→  tokenUsage,
 38→  onInputChange,
 39→  onSend,
 40→}: ChatInputProps) {
 41→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 42→  const pendingSelectionRef = useRef<{ start: number; end: number } | undefined>();
 43→  const shouldShowTodoPanel = todoTree.some(
 44→    todo => todo.status !== 'completed' || todo.children.some(group => group.todos.some(item => item.status !== 'completed')),
 45→  );
 46→  const [selection, setSelection] = useState({ start: input.length, end: input.length });
 47→  const [activeSkillIndex, setActiveSkillIndex] = useState(0);
 48→  const [dismissedSkillCommandKey, setDismissedSkillCommandKey] = useState<string | undefined>();
 49→  const modelCandidates = useMemo(() => {
 50→    if (availableModels.length === 0) {
 51→      return [selectedModel];
 52→    }
 53→    if (availableModels.includes(selectedModel)) {
 54→      return availableModels;
 55→    }
 56→    return [selectedModel, ...availableModels];
 57→  }, [availableModels, selectedModel]);
 58→  const selectedModelLabel = selectedModel;
 59→  const tokenPercent = getTokenUsagePercent(tokenUsage.used, tokenUsage.capacity);
 60→  const tokenRingColor = tokenPercent >= 90 ? 'hsl(var(--destructive))' : tokenPercent >= 70 ? 'hsl(38 92% 50%)' : 'hsl(142 72% 36%)';
 61→  const tokenUsageTitle = `Token 使用量：${tokenUsage.used.toLocaleString('en-US')} / ${tokenUsage.capacity.toLocaleString('en-US')}`;
 62→  const skillCommand = useMemo(() => findSkillCommand(input, selection.start), [input, selection.start]);
 63→  const skillCommandKey = skillCommand ? `${skillCommand.start}:${skillCommand.end}:${skillCommand.query}` : undefined;
 64→  const skillSuggestions = useMemo(
 65→    () => skillCommand ? filterSkillNames(skills, skillCommand.query) : [],
 66→    [skills, skillCommand],
 67→  );
 68→  const visibleSkillSuggestions = useMemo(() => skillSuggestions.slice(0, 6), [skillSuggestions]);
 69→  const shouldShowSkillMenu = !!skillCommand && visibleSkillSuggestions.length > 0 && dismissedSkillCommandKey !== skillCommandKey;
 70→
 71→  useEffect(() => {
 72→    const textarea = textareaRef.current;
 73→    if (!textarea) {
 74→      return;
 75→    }
 76→
 77→    textarea.style.height = '0px';
 78→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
 79→  }, [input]);
 80→
 81→  useEffect(() => {
 82→    if (dismissedSkillCommandKey && dismissedSkillCommandKey !== skillCommandKey) {
 83→      setDismissedSkillCommandKey(undefined);
 84→    }
 85→  }, [dismissedSkillCommandKey, skillCommandKey]);
 86→
 87→  useEffect(() => {
 88→    setActiveSkillIndex(0);
 89→  }, [skillCommandKey]);
 90→
 91→  useEffect(() => {
 92→    const pendingSelection = pendingSelectionRef.current;
 93→    const textarea = textareaRef.current;
 94→    if (!pendingSelection || !textarea) {
 95→      return;
 96→    }
 97→
 98→    textarea.focus();
 99→    textarea.setSelectionRange(pendingSelection.start, pendingSelection.end);
100→    setSelection({
101→      start: pendingSelection.start,
102→      end: pendingSelection.end,
103→    });
104→    pendingSelectionRef.current = undefined;
105→  }, [input]);
106→
107→  const applySkill = (skillName: string) => {
108→    const nextValue = insertSkillCommand(input, selection.start, selection.end, skillName);
109→    pendingSelectionRef.current = {
110→      start: nextValue.selectionStart,
111→      end: nextValue.selectionEnd,
112→    };
113→    onInputChange(nextValue.value);
114→    setDismissedSkillCommandKey(undefined);
115→  };
116→
117→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
118→    if (e.nativeEvent.isComposing) {
119→      return;
120→    }
121→
122→    if (shouldShowSkillMenu) {
123→      if (e.key === 'ArrowDown') {
124→        e.preventDefault();
125→        setActiveSkillIndex(index => (index + 1) % visibleSkillSuggestions.length);
126→        return;
127→      }
128→
129→      if (e.key === 'ArrowUp') {
130→        e.preventDefault();
131→        setActiveSkillIndex(index => (index - 1 + visibleSkillSuggestions.length) % visibleSkillSuggestions.length);
132→        return;
133→      }
134→
135→      if (e.key === 'Escape') {
136→        e.preventDefault();
137→        setDismissedSkillCommandKey(skillCommandKey);
138→        return;
139→      }
140→
141→      if (e.key === 'Enter' && !e.shiftKey) {
142→        e.preventDefault();
143→        applySkill(visibleSkillSuggestions[activeSkillIndex] ?? visibleSkillSuggestions[0]);
144→        return;
145→      }
146→    }
147→
148→    if (e.key === 'Enter' && !e.shiftKey) {
149→      e.preventDefault();
150→      onSend();
151→    }
152→  };
153→
154→  return (
155→    <div className="chat-input-top-gap bg-background/95 px-4 pb-4 pt-2.5 backdrop-blur supports-[backdrop-filter]:bg-background/60">
156→      <div className="chat-input-todo-stack mx-auto flex max-w-3xl flex-col gap-0">
157→        {shouldShowTodoPanel && (
158→          <div className="pointer-events-auto">
159→            <TodoListBlock todoTree={todoTree} isLoading={isLoading} attachedToComposer />
160→          </div>
161→        )}
162→
163→        <div
164→          className={cn(
165→            'relative rounded-2xl border bg-background shadow-sm focus-within:ring-1 focus-within:ring-ring transition-all',
166→          )}
167→        >
168→          <Textarea
