 13→export const generateId = (() => {
 14→  let counter = 0;
 15→  return () => {
 16→    if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) {
 17→      return crypto.randomUUID();
 18→    }
 19→    counter += 1;
 20→    return `${Date.now()}-${counter}`;
 21→  };
 22→})();
