 24→export function extractSingleLinePreview(content: string, maxLen = 120): string {
 25→  const singleLine = content.replace(/\s+/g, ' ').trim();
 26→  if (!singleLine) return '';
 27→  return singleLine.length > maxLen ? `${singleLine.slice(0, maxLen)}...` : singleLine;
 28→}
