 30→export function extractTaskDescription(content: string): string | undefined {
 31→  try {
 32→    const parsed = JSON.parse(content) as { description?: unknown };
 33→    if (typeof parsed.description === 'string' && parsed.description.trim()) {
 34→      return parsed.description.trim();
 35→    }
 36→  } catch {
 37→    return undefined;
 38→  }
 39→
 40→  return undefined;
