109→function inferLanguageFromPath(filePath?: string): string | undefined {
110→  if (!filePath) return undefined;
111→  const ext = filePath.split('.').pop()?.toLowerCase();
112→  switch (ext) {
113→    case 'ts':
114→    case 'tsx':
115→    case 'js':
116→    case 'jsx':
117→    case 'json':
118→    case 'md':
119→    case 'py':
120→    case 'sh':
121→    case 'bash':
122→    case 'yml':
123→    case 'yaml':
124→    case 'css':
125→    case 'html':
126→      return ext;
127→    default:
128→      return ext || undefined;
129→  }
130→}
