155→export function buildToolDetailFromArgs(
156→  toolName: string,
157→  args: Record<string, unknown>,
158→  status: ToolDetailStatus,
159→  output?: string,
160→): ToolDetail | undefined {
161→  if (toolName === TOOL_WRITE_FILE) {
