194→export const getEventLabel = (msg: Message) => {
195→  if (!msg.event || msg.event === 'assistant' || msg.event === 'user') return null;
196→
197→  const baseLabel = EVENT_LABELS[msg.event];
198→
199→  // 带工具名的标签
200→  if (msg.event === 'tool-input' || msg.event === 'tool-call' || msg.event === 'tool-call-result') {
201→    if (msg.toolName) {
